# Inspect and parse the CONTEXT to extract puzzles and BOX_INDEX, then run the checks.
text = CONTEXT.read(0, None)
lines = [l.strip() for l in text.splitlines()]

def extract_block(label):
    try:
        i = lines.index(label)
    except ValueError:
        return None
    block = []
    j = i+1
    # collect next 9 non-empty lines
    while j < len(lines) and len(block) < 9:
        if lines[j] != "":
            block.append(lines[j])
        j += 1
    return block

orig_block = extract_block("ORIGINAL_PUZZLE:")
sol_block = extract_block("SOLUTION_PUZZLE:")

# find BOX_INDEX line
box_index = None
for l in lines:
    if l.startswith("BOX_INDEX:"):
        try:
            box_index = int(l.split(":",1)[1].strip())
        except:
            pass

# Basic validation
if orig_block is None or sol_block is None or box_index is None:
    result = {"index": box_index if box_index is not None else 0,
              "ok": False,
              "issue": "failed to parse puzzles or BOX_INDEX"}
else:
    # parse into 9x9 arrays of ints
    def to_grid(block):
        grid = []
        for row in block:
            # ensure row has 9 chars
            row = row.strip()
            if len(row) != 9 or any(ch not in "0123456789" for ch in row):
                return None
            grid.append([int(ch) for ch in row])
        return grid

    orig_grid = to_grid(orig_block)
    sol_grid = to_grid(sol_block)

    if orig_grid is None or sol_grid is None:
        result = {"index": box_index,
                  "ok": False,
                  "issue": "invalid puzzle row formatting"}
    else:
        if not (0 <= box_index <= 8):
            result = {"index": box_index, "ok": False, "issue": "BOX_INDEX out of range"}
        else:
            r0 = (box_index // 3) * 3
            c0 = (box_index % 3) * 3
            # check given cells match
            mismatch = None
            for dr in range(3):
                for dc in range(3):
                    r = r0 + dr
                    c = c0 + dc
                    o = orig_grid[r][c]
                    s = sol_grid[r][c]
                    if o != 0 and o != s:
                        mismatch = (r, c, o, s)
                        break
                if mismatch:
                    break
            if mismatch:
                r,c,o,s = mismatch
                issue = f"given cell mismatch at ({r},{c}): original {o} vs solution {s}"
                result = {"index": box_index, "ok": False, "issue": issue}
            else:
                # check solution box contains digits 1..9 exactly once
                vals = []
                for dr in range(3):
                    for dc in range(3):
                        vals.append(sol_grid[r0+dr][c0+dc])
                counts = {d: vals.count(d) for d in range(1,10)}
                missing = [d for d,cnt in counts.items() if cnt == 0]
                duplicates = [d for d,cnt in counts.items() if cnt > 1]
                if missing or duplicates:
                    parts = []
                    if missing:
                        parts.append("missing " + ",".join(map(str,missing)))
                    if duplicates:
                        parts.append("duplicates " + ",".join(map(str,duplicates)))
                    issue = "box digits invalid: " + "; ".join(parts)
                    result = {"index": box_index, "ok": False, "issue": issue}
                else:
                    result = {"index": box_index, "ok": True, "issue": ""}

# Return final structured result
done(result)
